    46	void dft_lte(int32_t *z,struct complex16 *input, int32_t Msc_PUSCH, uint8_t Nsymb)
    47	{
    48	  simde__m128i dft_in128[4][1200], dft_out128[4][1200];
    49	  uint32_t *dft_in0=(uint32_t*)dft_in128[0],*dft_out0=(uint32_t*)dft_out128[0];
    50	  uint32_t *dft_in1=(uint32_t*)dft_in128[1],*dft_out1=(uint32_t*)dft_out128[1];
    51	  uint32_t *dft_in2=(uint32_t*)dft_in128[2],*dft_out2=(uint32_t*)dft_out128[2];
    52	  //  uint32_t *dft_in3=(uint32_t*)dft_in128[3],*dft_out3=(uint32_t*)dft_out128[3];
    53	
    54	  uint32_t *d0,*d1,*d2,*d3,*d4,*d5,*d6,*d7,*d8,*d9,*d10,*d11;
    55	
    56	  uint32_t *z0,*z1,*z2,*z3,*z4,*z5,*z6,*z7,*z8,*z9,*z10,*z11;
    57	  uint32_t i, ip;
    58	  simde__m128i norm128;
    59	  //  printf("Doing lte_dft for Msc_PUSCH %d\n",Msc_PUSCH);
    60	
    61	  d0 = (uint32_t *)input;
    62	  d1 = d0+Msc_PUSCH;
    63	  d2 = d1+Msc_PUSCH;
    64	  d3 = d2+Msc_PUSCH;
    65	  d4 = d3+Msc_PUSCH;
    66	  d5 = d4+Msc_PUSCH;
    67	  d6 = d5+Msc_PUSCH;
    68	  d7 = d6+Msc_PUSCH;
    69	  d8 = d7+Msc_PUSCH;
    70	  d9 = d8+Msc_PUSCH;
    71	  d10 = d9+Msc_PUSCH;
    72	  d11 = d10+Msc_PUSCH;
    73	
    74	  //  printf("symbol 0 (d0 %p, d %p)\n",d0,d);
    75	  for (i=0,ip=0; i<Msc_PUSCH; i++,ip+=4) {
    76	    dft_in0[ip]   =  d0[i];
    77	    dft_in0[ip+1] =  d1[i];
    78	    dft_in0[ip+2] =  d2[i];
    79	    dft_in0[ip+3] =  d3[i];
    80	    dft_in1[ip]   =  d4[i];
    81	    dft_in1[ip+1] =  d5[i];
    82	    dft_in1[ip+2] =  d6[i];
    83	    dft_in1[ip+3] =  d7[i];
    84	    dft_in2[ip]   =  d8[i];
    85	    dft_in2[ip+1] =  d9[i];
    86	    dft_in2[ip+2] =  d10[i];
    87	    dft_in2[ip+3] =  d11[i];
    88	    //    printf("dft%d %d: %d,%d,%d,%d\n",Msc_PUSCH,ip,d0[i],d1[i],d2[i],d3[i]);
    89	
    90	    //    dft_in_re2[ip+1] =  d9[i];
    91	    //    dft_in_re2[ip+2] =  d1
... [truncated] ...
 = get_dft(Msc_PUSCH);
    96	  if (dftsize == DFT_SIZE_IDXTABLESIZE) {
    97	    LOG_E(PHY, "Internal error, not modulating the slot, Msc_PUSCH = %d\n", Msc_PUSCH);
    98	    return;
    99	  }
   100	
   101	  switch (Msc_PUSCH) {
   102	  case 12:
   103	    dft(dftsize, (int16_t *)dft_in0, (int16_t *)dft_out0, 0);
   104	    dft(dftsize, (int16_t *)dft_in1, (int16_t *)dft_out1, 0);
   105	    dft(dftsize, (int16_t *)dft_in2, (int16_t *)dft_out2, 0);
   106	    norm128 = simde_mm_set1_epi16(9459);
   107	    for (i = 0; i < 12; i++) {
   108	      ((simde__m128i *)dft_out0)[i] = simde_mm_slli_epi16(simde_mm_mulhi_epi16(((simde__m128i *)dft_out0)[i], norm128), 1);
   109	      ((simde__m128i *)dft_out1)[i] = simde_mm_slli_epi16(simde_mm_mulhi_epi16(((simde__m128i *)dft_out1)[i], norm128), 1);
   110	      ((simde__m128i *)dft_out2)[i] = simde_mm_slli_epi16(simde_mm_mulhi_epi16(((simde__m128i *)dft_out2)[i], norm128), 1);
   111	    }
   112	
   113	    break;
   114	
   115	  default:
   116	    dft(dftsize, (int16_t *)dft_in0, (int16_t *)dft_out0, 1);
   117	    dft(dftsize, (int16_t *)dft_in1, (int16_t *)dft_out1, 1);
   118	    dft(dftsize, (int16_t *)dft_in2, (int16_t *)dft_out2, 1);
   119	    break;
   120	  }
   121	
   122	  z0 = (uint32_t *)z;
   123	  z1 = z0+Msc_PUSCH;
   124	  z2 = z1+Msc_PUSCH;
   125	  z3 = z2+Msc_PUSCH;
   126	  z4 = z3+Msc_PUSCH;
   127	  z5 = z4+Msc_PUSCH;
   128	  z6 = z5+Msc_PUSCH;
   129	  z7 = z6+Msc_PUSCH;
   130	  z8 = z7+Msc_PUSCH;
   131	  z9 = z8+Msc_PUSCH;
   132	  z10 = z9+Msc_PUSCH;
   133	  z11 = z10+Msc_PUSCH;
   134	
   135	  //  printf("symbol0 (dft)\n");
   136	  for (i=0,ip=0; i<Msc_PUSCH; i++,ip+=4) {
   137	    z0[i]     = dft_out0[ip];
   138	    //    printf("%d,%d,",((short*)&z0[i])[0],((short*)&z0[i])[1]);
   139	    z1[i]     = dft_out0[ip+1];
   140	    z2[i]     = dft_out0[ip+2];
   141	    z3[i]     = dft_out0[ip+3];
   142	    z4[i]     = dft_out1[ip+0];
   143	    z5[i]     = dft_out1[ip+1];
   144	    z6[i]     = dft_out1[ip+2];
   145	    z7[i]     = dft_out1[ip+3];
   146	    z8[i]     = dft_out2[ip];
   147	    z9[i]     = dft_out2[ip+1];
   148	    z10[i]    = dft_out2[ip+2];
   149	    z11[i]    = dft_out2[ip+3];
   150	    //    printf("out dft%d %d: %d,%d,%d,%d,%d,%d,%d,%d\n",Msc_PUSCH,ip,z0[i],z1[i],z2[i],z3[i],z4[i],z5[i],z6[i],z7[i]);
   151	
   152	  }
   153	
   154	  //  printf("\n");
   155	}
   156	
   157	void ulsch_modulation(int32_t **txdataF,
   158	                      short amp,
   159	                      uint32_t frame,
   160	                      uint32_t subframe,
   161	                      LTE_DL_FRAME_PARMS *frame_parms,
   162	                      LTE_UE_ULSCH_t *ulsch)
   163	{
   164	
   165	  uint8_t qam64_table_offset_re = 0;
   166	  uint8_t qam64_table_offset_im = 0;
   167	  uint8_t qam16_table_offset_re = 0;
   168	  uint8_t qam16_table_offset_im = 0;
   169	  short gain_lin_QPSK;
   170	
   171	  DevAssert(frame_parms);
   172	
   173	  int re_offset,re_offset0,i,ulsch_Msymb,j,k,nsymb,Msc_PUSCH,l;
   174	  //  uint8_t harq_pid = (rag_flag == 1) ? 0 : subframe2harq_pid_tdd(frame_parms->tdd_config,subframe);
   175	  uint8_t harq_pid = subframe2harq_pid(frame_parms,frame,subframe);
   176	  uint8_t Q_m;
   177	  int32_t *txptr;
   178	  uint32_t symbol_offset;
   179	  uint16_t first_rb;
   180	  uint16_t nb_rb;
   181	  int G;
   182	
   183	  uint32_t x1, x2, s=0;
   184	  uint8_t c;
   185	
   186	  if (!ulsch) {
   187	    printf("ulsch_modulation.c: Null ulsch\n");
   188	    return;
   189	  }
   190	
   191	  // x1 is set in lte_gold_generic
   192	  x2 = (ulsch->rnti<<14) + (subframe<<9) + frame_parms->Nid_cell; //this is c_init in 36.211 Sec 6.3.1
   193	
   194	  if (harq_pid>=8) {
   195	    printf("ulsch_modulation.c: Illegal harq_pid %d\n",harq_pid);
   196	    return;
   197	  }
   198	
   199	  first_rb = ulsch->harq_processes[harq_pid]->first_rb;
   200	  nb_rb = ulsch->harq_processes[harq_pid]->nb_rb;

  nb_rb = ulsch->harq_processes[harq_pid]->nb_rb;

  if (nb_rb == 0) {
    printf("ulsch_modulation.c: Frame %u, Subframe %u Illegal nb_rb %d\n",frame,subframe,nb_rb);
    return;
  }

  if (first_rb > frame_parms->N_RB_UL) {
    printf("ulsch_modulation.c: Frame %u, Subframe %u Illegal first_rb %d\n",frame,subframe,first_rb);
    return;
  }

  VCD_SIGNAL_DUMPER_DUMP_FUNCTION_BY_NAME(VCD_SIGNAL_DUMPER_FUNCTIONS_UE_ULSCH_MODULATION, VCD_FUNCTION_IN);

  Q_m = get_Qm_ul(ulsch->harq_processes[harq_pid]->mcs);

  G = (int)ulsch->harq_processes[harq_pid]->nb_rb * (12 * Q_m) * (ulsch->Nsymb_pusch);


  // Mapping
  nsymb = (frame_parms->Ncp==0) ? 14:12;
  Msc_PUSCH = ulsch->harq_processes[harq_pid]->nb_rb*12;

#ifdef DEBUG_ULSCH_MODULATION
  LOG_D(PHY,"ulsch_modulation.c: Doing modulation (rnti %x,x2 %x) for G=%d bits, harq_pid %d , nb_rb %d, Q_m %d, Nsymb_pusch %d (nsymb %d), subframe %d\n",
        ulsch->rnti,x2,G,harq_pid,ulsch->harq_processes[harq_pid]->nb_rb,Q_m, ulsch->Nsymb_pusch,nsymb,subframe);
#endif

  // scrambling (Note the placeholding bits are handled in ulsch_coding.c directly!)
  //printf("ulsch bits: ");
  s = lte_gold_generic(&x1, &x2, 1);
  k=0;

  //printf("G %d\n",G);
  for (i=0; i<(1+(G>>5)); i++) {
    for (j=0; j<32; j++,k++) {
      c = (uint8_t)((s>>j)&1);

      if (ulsch->h[k] == PUSCH_x) {
        //  printf("i %d: PUSCH_x\n",i);
        ulsch->b_tilde[k] = 1;
      } else if (ulsch->h[k] == PUSCH_y) {
        //  printf("i %d: PUSCH_y\n",i);
        ulsch->b_tilde[k] = ulsch->b_tilde[k-1];
      } else {
        ulsch->b_tilde[k] = (ulsch->h[k]+c)&1;
        //  printf("i %d : %d (h %d c %d)\n", (i<<5)+j,ulsch->b_tilde[k],ulsch->h[k],c);
      }

    }

    s = lte_gold_generic(&x1, &x2, 0);
  }

  //printf("\n");


  gain_lin_QPSK = (short)((amp*ONE_OVER_SQRT2_Q15)>>15);


  // Modulation

  ulsch_Msymb = G/Q_m;
  /// Modulated "d"-sequences (for definition see 36-211 V8.6 2009-03, p.14)
  struct complex16 d[MAX_NUM_RE] __attribute__((aligned(32)));
  if(ulsch->cooperation_flag == 2)
    // For Distributed Alamouti Scheme in Collabrative Communication
  {
    for (i=0,j=Q_m; i<ulsch_Msymb; i+=2,j+=2*Q_m) {

      switch (Q_m) {

      case 2:


        //UE1, -x1*
        d[i].r = (ulsch->b_tilde[j] == 1)  ? (gain_lin_QPSK) : -gain_lin_QPSK;
        d[i].i = (ulsch->b_tilde[j+1] == 1)? (-gain_lin_QPSK) : gain_lin_QPSK;
        //      if (i<Msc_PUSCH)
        //  printf("input %d (%p): %d,%d\n", i,&ulsch->d[i],((int16_t*)&ulsch->d[i])[0],((int16_t*)&ulsch->d[i])[1]);

        // UE1, x0*
        d[i+1].r = (ulsch->b_tilde[j-2] == 1)  ? (-gain_lin_QPSK) : gain_lin_QPSK;
        d[i+1].i = (ulsch->b_tilde[j-1] == 1)? (gain_lin_QPSK) : -gain_lin_QPSK;

        break;

      case 4:


        //UE1,-x1*
        qam16_table_offset_re = 0;
        qam16_table_offset_im = 0;

        if (ulsch->b_tilde[j] == 1)
          qam16_table_offset_re+=2;

        if (ulsch->b_tilde[j+1] == 1)
          qam16_table_offset_im+=2;



        if (ulsch->b_tilde[j+2] == 1)
          qam16_table_offset_re+=1;

        if (ulsch->b_tilde[j+3] == 1)
          qam16_table_offset_im+=1;


        d[i].r =-(int16_t)(((int32_t)amp*qam16_table[qam16_table_offset_re])>>15);
        d[i].i =(int16_t)(((int32_t)amp*qam16_table[qam16_table_offset_im])>>15);

        //UE1,x0*
        qam16_table_offset_re = 0;
        qam16_table_offset_im = 0;

        if (ulsch->b_tilde[j-4] == 1)
          qam16_table_offset_re+=2;

        if (ulsch->b_tilde[j-3] == 1)
          qam16_table_offset_im+=2;


        if (ulsch->b_tilde[j-2] == 1)
          qam16_table_offset_re+=1;

        if (ulsch->b_tilde[j-1] == 1)
          qam16_table_offset_im+=1;


        //    ((int16_t*)&ulsch->d[i+1])[0]=-(int16_t)(((int32_t)amp*qam16_table[qam16_table_offset_re])>>15);
        //    ((int16_t*)&ulsch->d[i+1])[1]=(int16_t)(((int32_t)amp*qam16_table[qam16_table_offset_im])>>15);
        d[i+1].r=(int16_t)(((int32_t)amp*qam16_table[qam16_table_offset_re])>>15);
        d[i+1].i=-(int16_t)(((int32_t)amp*qam16_table[qam16_table_offset_im])>>15);


        break;

      case 6:



        //UE1,-x1*FPGA_UE
        qam64_table_offset_re = 0;
        qam64_table_offset_im = 0;

        if (ulsch->b_tilde[j] == 1)
          qam64_table_offset_re+=4;

        if (ulsch->b_tilde[j+1] == 1)
          qam64_table_offset_im+=4;

